final:
module top_module (
    input g,
    input w,
    input k,
    input t,
    output reg nx
);
    always @(*) begin
        case ({g, w, k, t})
            4'b0111: nx = 1'b1;
            4'b0011: nx = 1'b0;
            4'b1100: nx = 1'b0;
            4'b0110: nx = 1'b1;
            4'b0010: nx = 1'b1;
            4'b0000: nx = 1'b0;
            4'b1101: nx = 1'b1;
            4'b0100: nx = 1'b1;
            4'b1011: nx = 1'b0;
            4'b0101: nx = 1'b0;
            4'b0001: nx = 1'b1;
            4'b1000: nx = 1'b0;
            4'b1010: nx = 1'b0;
            4'b1111: nx = 1'b1;
            4'b1001: nx = 1'b0;
            4'b1110: nx = 1'b0;
        endcase
    end
endmodule
